# frozen_string_literal: true

# Hardcoded plans for the spike. In production the plan is generated by the LLM (W1.3).
# Each plan = list of revisions. Each revision: summary (commit msg) + prompt (for Claude CLI).

module Plans
  TODO_LIST = [
