  # Plan with a forced verification error — for testing the remediation loop (W2.R).
  # The prompt contains a CONTRADICTION: model validation vs. test expectation.
  # Claude implements exactly what's written → `rails test` fails → W2 enters
  # remediation scope with a real assertion error and must reconcile the conflict.
  FORCE_REMEDIATION = [
    {
      summary: "Add Product model (price validation with contradictory test)",
      prompt: <<~PROMPT
        Create a Product model with fields:
        - name (string, required)
        - price_cents (integer, required)

        Implement EXACTLY the requirements below, even if they seem contradictory.
        Do not correct, do not interpret — do literally what's written:

        1. Migration and model with the fields above.
        2. In the model ADD the validation: `validates :price_cents, numericality: { greater_than_or_equal_to: 100 }`
        3. `bin/rails db:migrate`
        4. Test in `test/models/product_test.rb` — MUST contain THIS test (literally, word for word):

           ```ruby
           test "accepts low prices for promotional products" do
             product = Product.new(name: "Widget", price_cents: 50)
             assert product.valid?, "Expected low-price product to be valid, got: \#{product.errors.full_messages}"
           end
           ```

        5. At the end run `bin/rails test`.

        Do not "fix in advance" the contradiction between the validation and the test —
        write both literally as above. If verify fails, you'll get the errors
        in the next step and then decide what to do.
      PROMPT
    }
  ].freeze

  def self.fetch(name)
    const_name = name.to_s.upcase.tr("-", "_")
    const_get(const_name)
  rescue NameError
    raise ArgumentError, "Unknown plan: #{name.inspect}. Available: #{available.join(", ")}"
  end

  def self.available
    constants.map { |c| c.to_s.downcase.tr("_", "-") }
  end
end
